            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}><span style={{fontSize:16,color:"#1DB954"}}>🎵</span><span style={{fontSize:13,fontWeight:600,color:C.dark}}>Playlist</span></div>
