function Oraciones({oraciones,setOraciones,newOr,setNewOr,showForm,setShowForm,user}) {
  function submit() {
    if(!newOr.titulo.trim()||!newOr.texto.trim()) return;
    setOraciones(p=>[...p,{id:Date.now(),...newOr,autor:user.nombre,fecha:hoyDDMM()+"/2026"}]);
    setNewOr({titulo:"",texto:""});setShowForm(false);
  }
  return (
    <div style={{maxWidth:800}}>
      <SectionTitle title="Oraciones" subtitle="Compartidas por los integrantes" action={<Btn onClick={()=>setShowForm(true)}>+ Nueva oración</Btn>}/>
      {showForm&&(
        <Card style={{marginBottom:16,border:`1px solid ${C.primary}40`}}>
          <div style={{fontFamily:"'Poppins',sans-serif",fontSize:14,fontWeight:600,color:C.dark,marginBottom:14}}>Nueva oración</div>
          <Input placeholder="Título de la oración" value={newOr.titulo} onChange={e=>setNewOr(p=>({...p,titulo:e.target.value}))} style={{marginBottom:10}}/>
          <textarea value={newOr.texto} onChange={e=>setNewOr(p=>({...p,texto:e.target.value}))} placeholder="Texto de la oración..." rows={4} style={{width:"100%",padding:"10px 14px",borderRadius:8,border:`1px solid ${C.border}`,fontSize:13,fontFamily:"Inter,sans-serif",resize:"vertical",boxSizing:"border-box",outline:"none",marginBottom:12}}/>
          <div style={{display:"flex",gap:8}}><Btn onClick={submit}>Publicar</Btn><Btn variant="ghost" onClick={()=>setShowForm(false)}>Cancelar</Btn></div>
        </Card>
      )}
      {oraciones.map(o=>(
        <Card key={o.id} style={{marginBottom:12,borderLeft:`4px solid ${C.gold}`}}>
          <div style={{fontFamily:"'Poppins',sans-serif",fontSize:14,fontWeight:600,color:C.dark,marginBottom:8}}>✦ {o.titulo}</div>
          <p style={{lineHeight:1.8,color:"#374151",margin:"0 0 12px",fontSize:14}}>{o.texto}</p>
          <div style={{fontSize:11,color:C.gray}}>👤 {o.autor} · {o.fecha}</div>
        </Card>
      ))}
    </div>
  );
}

